void array_prefix_max(int n, int *a, int *out)
/*@ With la lo
    Require
      0 <= n &&
      n + 1 <= INT_MAX &&
      Zlength(la) == n &&
      Zlength(lo) == n &&
      IntArray::full(a, n, la) *
