*/
{
    int i;
    int cur;

    if (n == 0) {
        return;
    }

    cur = a[0];
    out[0] = cur;
    /*@ Inv exists l1,
          1 <= i && i <= n@pre &&
          a == a@pre &&
          n == n@pre &&
          n + 1 <= INT_MAX &&
          out == out@pre &&
          n@pre == Zlength(la) &&
          n@pre == Zlength(lo) &&
          Zlength(l1) == i &&
